link.script:
(function(d,h,host){
  var deployed="https://ssscript-website.vercel.app/app.js";
  if(!host.endsWith(".webflow.io")){
    var s=d.createElement("script");
    s.src=deployed;s.defer=1;s.crossOrigin="anonymous";
    h.appendChild(s);return;
  }
  var p=d.createElement("link");
  p.rel="preload";p.as="script";p.href=deployed;p.crossOrigin="anonymous";
  h.appendChild(p);

  var l=d.createElement("script");
  l.src="https://localhost:6545/app.js";l.defer=1;
  l.onerror=function(){
    var f=d.createElement("script");
    f.src=deployed;f.defer=1;f.crossOrigin="anonymous";
    h.appendChild(f);
  };
  h.appendChild(l);
})(document,document.head,location.hostname);
